CREATE POLICY "Admins manage user roles INSERT" ON public.user_roles FOR INSERT TO authenticated WITH CHECK (public.has_role(auth.uid(), 'admin'));
CREATE POLICY "Admins manage user roles UPDATE" ON public.user_roles FOR UPDATE TO authenticated USING (public.has_role(auth.uid(), 'admin')) WITH CHECK (public.has_role(auth.uid(), 'admin'));
CREATE POLICY "Admins manage user roles DELETE" ON public.user_roles FOR DELETE TO authenticated USING (public.has_role(auth.uid(), 'admin'));